{% extends "base.html" %}
{% block title %}{{ deal.deal_id }} — Hiive Deal Monitor{% endblock %}

{% block content %}
<div class="space-y-6">

  <!-- Header -->
  <div class="flex items-start justify-between">
    <div>
      <div class="flex items-center gap-3">
        <h1 class="text-lg font-semibold text-neutral-900">{{ deal.deal_id }}</h1>
        <span class="rounded bg-neutral-100 px-2 py-0.5 text-xs font-medium text-neutral-600">
          {{ deal.stage | replace('_', ' ') | title }}
        </span>
      </div>
      {% if issuer %}
      <p class="mt-0.5 text-sm text-neutral-500">{{ issuer.name }} · {{ deal.shares | int | format_number }} shares @ ${{ "%.2f"|format(deal.price_per_share) }}</p>
      {% endif %}
    </div>
    <div class="flex items-center gap-3">
      <a href="/brief" class="text-sm text-neutral-400 hover:text-neutral-600">← Brief</a>
      {% if debug %}
      <a href="/debug/deal/{{ deal.deal_id }}" class="text-xs text-purple-500 hover:text-purple-700 font-mono">⟩ debug view</a>
      {% else %}
      <a href="?debug=1" class="text-xs text-neutral-300 hover:text-neutral-500">debug</a>
      {% endif %}
    </div>
  </div>

  <!-- Deal facts -->
  <div class="grid grid-cols-2 gap-3 sm:grid-cols-4">
    {% macro fact(label, value) %}
    <div class="rounded border border-neutral-100 bg-white px-4 py-3">
      <p class="text-xs text-neutral-400 uppercase tracking-wide">{{ label }}</p>
      <p class="mt-1 text-sm font-medium text-neutral-800">{{ value or '—' }}</p>
    </div>
    {% endmacro %}
    {{ fact("Stage entered", deal.stage_entered_at[:10] if deal.stage_entered_at else '—') }}
    {{ fact("Responsible", deal.responsible_party | replace('_', ' ') if deal.responsible_party else '—') }}
    {{ fact("ROFR deadline", deal.rofr_deadline[:10] if deal.rofr_deadline else 'None') }}
    {{ fact("Buyer", deal.buyer_id) }}
  </div>

  <!-- Event timeline -->
  <div>
    <h2 class="text-sm font-semibold text-neutral-700 mb-3">Event Timeline</h2>
    {% if events %}
    <div class="space-y-1">
      {% for ev in events | sort(attribute='occurred_at', reverse=True) %}
      <div class="flex items-start gap-3 text-xs">
        <span class="flex-shrink-0 text-neutral-400 font-mono">{{ ev.occurred_at[:10] }}</span>
        <span class="rounded px-1.5 py-0.5
          {% if ev.event_type == 'comm_outbound' %}bg-blue-50 text-blue-700
          {% elif ev.event_type == 'comm_inbound' %}bg-green-50 text-green-700
          {% elif ev.event_type == 'stage_transition' %}bg-neutral-100 text-neutral-600
          {% elif ev.event_type == 'comm_sent_agent_recommended' %}bg-purple-50 text-purple-700
          {% else %}bg-neutral-50 text-neutral-500{% endif %}
        ">{{ ev.event_type | replace('_', ' ') }}</span>
        <span class="text-neutral-600">{{ ev.summary }}</span>
      </div>
      {% endfor %}
    </div>
    {% else %}
    <p class="text-xs text-neutral-400">No events yet.</p>
    {% endif %}
  </div>

  <!-- Agent observations -->
  <div>
    <h2 class="text-sm font-semibold text-neutral-700 mb-3">Agent Observations ({{ observations | length }})</h2>
    {% if observations %}
    <div class="space-y-3">
      {% for obs in observations | sort(attribute='observed_at', reverse=True) %}
      <div class="rounded border border-neutral-100 bg-white px-4 py-3 text-xs" x-data="{ show: false }">
        <div class="flex items-center justify-between">
          <div class="flex items-center gap-2">
            <span class="font-mono text-neutral-400">{{ obs.observed_at[:16] }}</span>
            {% if obs.severity == 'escalate' %}
              <span class="rounded-full bg-red-100 px-2 py-0.5 font-semibold text-red-700">ESCALATE</span>
            {% elif obs.severity == 'act' %}
              <span class="rounded-full bg-amber-100 px-2 py-0.5 font-semibold text-amber-700">ACT</span>
            {% elif obs.severity == 'watch' %}
              <span class="rounded-full bg-blue-100 px-2 py-0.5 font-semibold text-blue-600">WATCH</span>
            {% else %}
              <span class="rounded-full bg-neutral-100 px-2 py-0.5 text-neutral-500">INFO</span>
            {% endif %}
            {% for dim in obs.reasoning_parsed.get('dimensions_triggered', []) %}
            <span class="bg-neutral-100 px-1.5 py-0.5 rounded text-neutral-500">{{ dim | replace('_', ' ') }}</span>
            {% endfor %}
          </div>
          <button x-on:click="show = !show" class="text-neutral-400 hover:text-neutral-600"
            x-text="show ? 'Hide reasoning' : 'Show reasoning'"></button>
        </div>

        <div x-show="show" x-cloak class="mt-3 space-y-2">
          {% if obs.reasoning_parsed.get('error') %}
          <div class="rounded bg-red-50 border border-red-100 px-3 py-2 text-xs text-red-600">
            LLM error: {{ obs.reasoning_parsed.get('error') }}
          </div>
          {% else %}
          <p class="text-neutral-600 leading-relaxed">{{ obs.reasoning_parsed.get('severity_rationale', '') }}</p>
          {% set chain = obs.reasoning_parsed.get('enrichment_chain', []) %}
          {% if chain %}
          <div class="mt-2 space-y-1">
            <span class="text-xs font-medium text-neutral-400 uppercase tracking-wide">Enrichment steps ({{ chain|length }})</span>
            {% for step in chain %}
            <div class="rounded bg-neutral-50 border border-neutral-100 px-3 py-2 text-xs text-neutral-500">
              <span class="font-medium text-neutral-600">{{ step.get('tool_called', '?') | replace('_', ' ') }}</span>
              {% if step.get('rationale') %} — {{ step.get('rationale') }}{% endif %}
            </div>
            {% endfor %}
          </div>
          {% else %}
          <p class="text-xs text-neutral-400 italic">No enrichment performed — initial signals were sufficient.</p>
          {% endif %}
          {% endif %}
          {% if debug %}
          <pre class="rounded bg-neutral-50 p-3 text-xs text-neutral-500 overflow-auto max-h-64">{{ obs.reasoning_parsed | tojson(indent=2) }}</pre>
          {% endif %}
        </div>
      </div>
      {% endfor %}
    </div>
    {% else %}
    <p class="text-xs text-neutral-400">No observations yet — run a tick to analyze this deal.</p>
    {% endif %}
  </div>

  <!-- Interventions -->
  <div>
    <h2 class="text-sm font-semibold text-neutral-700 mb-3">Interventions ({{ interventions | length }})</h2>
    {% if interventions %}
    <div class="space-y-2">
      {% for iv in interventions | sort(attribute='created_at', reverse=True) %}
      <div class="rounded border border-neutral-100 bg-white px-4 py-3 text-xs">
        <div class="flex items-center gap-2 mb-1">
          <span class="font-mono text-neutral-400">{{ iv.created_at[:16] }}</span>
          <span class="bg-neutral-100 px-1.5 py-0.5 rounded text-neutral-600">{{ iv.intervention_type | replace('_', ' ') }}</span>
          <span class="{% if iv.status == 'pending' %}text-amber-600{% elif iv.status in ['approved','edited'] %}text-green-600{% else %}text-neutral-400{% endif %} font-medium">
            {{ iv.status }}
          </span>
        </div>
        <p class="text-neutral-600">{{ iv.draft_subject or (iv.draft_body[:120] + '…') }}</p>
      </div>
      {% endfor %}
    </div>
    {% else %}
    <p class="text-xs text-neutral-400">No interventions drafted yet.</p>
    {% endif %}
  </div>

</div>
{% endblock %}

"""Core FastAPI routes — brief, queue, deal detail, sim controls, clock API."""

from __future__ import annotations

import json

from fastapi import APIRouter, Form, HTTPException, Request
from fastapi.responses import HTMLResponse, RedirectResponse

from hiive_monitor.app import templates
from hiive_monitor.db import dao
from hiive_monitor.db.connection import get_domain_conn

router = APIRouter()


@router.get("/")
async def root():
    return RedirectResponse(url="/brief", status_code=307)


# ── Daily brief ───────────────────────────────────────────────────────────────


@router.get("/brief")
async def daily_brief(request: Request, debug: str = ""):
    from hiive_monitor import clock as clk

    conn = get_domain_conn()
    tick = dao.get_last_completed_tick(conn)
    open_ivs = dao.get_open_interventions(conn)

    # Enrich each intervention with deal info
    items = []
    for iv in open_ivs:
        deal = dao.get_deal(conn, iv["deal_id"])
        obs = dao.get_observations(conn, iv["deal_id"])
        latest_obs = obs[-1] if obs else None
        reasoning = json.loads(latest_obs["reasoning"]) if latest_obs and latest_obs.get("reasoning") else {}
        items.append({
            **iv,
            "deal": deal,
            "reasoning_summary": reasoning.get("severity_rationale", ""),
            "dimensions_triggered": reasoning.get("dimensions_triggered", []),
        })
    conn.close()

    return templates.TemplateResponse(
        request, "brief.html",
        {"items": items, "tick": tick, "now": clk.now().isoformat(), "debug": debug == "1"},
    )


@router.post("/interventions/{intervention_id}/approve")
async def approve_intervention(request: Request, intervention_id: str):
    from hiive_monitor import clock as clk

    conn = get_domain_conn()
    iv = dao.get_intervention(conn, intervention_id)
    if not iv:
        conn.close()
        raise HTTPException(status_code=404, detail="Intervention not found")

    dao.approve_intervention_atomic(conn, intervention_id, simulated_timestamp=clk.now())
    conn.close()

    # Return HTMX partial — replace the card with "sent" state
    return HTMLResponse(
        f'<div class="rounded border border-green-200 bg-green-50 px-4 py-3 text-sm text-green-700">'
        f'✓ Approved and marked sent for deal {iv["deal_id"]}'
        f'</div>'
    )


@router.post("/interventions/{intervention_id}/dismiss")
async def dismiss_intervention(request: Request, intervention_id: str):
    conn = get_domain_conn()
    iv = dao.get_intervention(conn, intervention_id)
    if not iv:
        conn.close()
        raise HTTPException(status_code=404, detail="Intervention not found")

    dao.update_intervention_status(conn, intervention_id, status="dismissed")
    conn.close()

    return HTMLResponse(
        f'<div class="text-xs text-neutral-400 px-4 py-2">Dismissed — {iv["deal_id"]}</div>'
    )


@router.post("/interventions/{intervention_id}/confirm-edit")
async def confirm_edit(request: Request, intervention_id: str, final_text: str = Form(...)):
    from hiive_monitor import clock as clk

    conn = get_domain_conn()
    iv = dao.get_intervention(conn, intervention_id)
    if not iv:
        conn.close()
        raise HTTPException(status_code=404, detail="Intervention not found")

    dao.edit_intervention_atomic(
        conn, intervention_id, simulated_timestamp=clk.now(), final_text=final_text
    )
    conn.close()

    return HTMLResponse(
        f'<div class="rounded border border-blue-200 bg-blue-50 px-4 py-3 text-sm text-blue-700">'
        f'✓ Edited draft sent for deal {iv["deal_id"]}'
        f'</div>'
    )


# ── Queue ─────────────────────────────────────────────────────────────────────


@router.get("/queue")
async def queue(request: Request, severity: str = "", stage: str = "", issuer: str = ""):
    conn = get_domain_conn()
    open_ivs = dao.get_open_interventions(conn)
    items = []
    for iv in open_ivs:
        deal = dao.get_deal(conn, iv["deal_id"])
        if severity and iv.get("severity") != severity:
            continue
        if stage and deal and deal.get("stage") != stage:
            continue
        if issuer and deal and deal.get("issuer_id") != issuer:
            continue
        items.append({**iv, "deal": deal})
    conn.close()
    return templates.TemplateResponse(
        request, "queue.html",
        {"items": items, "severity": severity, "stage": stage, "issuer": issuer},
    )


# ── Deal detail ───────────────────────────────────────────────────────────────


@router.get("/deals/{deal_id}")
async def deal_detail(request: Request, deal_id: str, debug: str = ""):
    conn = get_domain_conn()
    deal = dao.get_deal(conn, deal_id)
    if deal is None:
        conn.close()
        raise HTTPException(status_code=404, detail="Deal not found")

    events = dao.get_events(conn, deal_id)
    observations = dao.get_observations(conn, deal_id)
    interventions = dao.get_interventions(conn, deal_id)
    issuer = dao.get_issuer(conn, deal["issuer_id"])
    conn.close()

    obs_enriched = []
    for obs in observations:
        reasoning = json.loads(obs["reasoning"]) if obs.get("reasoning") else {}
        obs_enriched.append({**obs, "reasoning_parsed": reasoning})

    return templates.TemplateResponse(
        request, "deal_detail.html",
        {
            "deal": deal,
            "events": events,
            "observations": obs_enriched,
            "interventions": interventions,
            "issuer": issuer,
            "debug": debug == "1",
        },
    )


# ── Simulation controls ───────────────────────────────────────────────────────


@router.get("/sim")
async def sim_page(request: Request):
    from hiive_monitor import clock as clk
    return templates.TemplateResponse(
        request, "sim.html", {"now": clk.now().isoformat()}
    )


@router.post("/sim/advance")
async def advance_sim(request: Request, days: int = Form(...)):
    from hiive_monitor import clock as clk
    from hiive_monitor.agents.monitor import run_tick

    try:
        clk.get_clock().advance(days)
    except RuntimeError:
        return HTMLResponse(
            '<div class="rounded border border-red-200 bg-red-50 px-4 py-2 text-xs text-red-600">'
            'Cannot advance clock in real-time mode — restart with CLOCK_MODE=simulated.'
            '</div>',
            status_code=400,
        )

    tick_id = run_tick(mode="simulated")

    return HTMLResponse(
        f'<div class="rounded border border-neutral-200 bg-neutral-50 px-4 py-3 text-sm">'
        f'Advanced {days} day(s). New tick: {tick_id[:8]}…'
        f'<a href="/brief" class="ml-3 font-medium text-neutral-700 underline">View Brief →</a>'
        f'</div>'
    )


# ── API ───────────────────────────────────────────────────────────────────────


@router.get("/api/clock")
async def clock_api():
    from hiive_monitor import clock as clk
    conn = get_domain_conn()
    tick = dao.get_last_completed_tick(conn)
    conn.close()
    return {
        "now": clk.now().isoformat(),
        "last_tick": tick["tick_id"] if tick else None,
        "last_tick_at": tick["tick_completed_at"] if tick else None,
    }


@router.post("/api/tick")
async def run_tick_api():
    from hiive_monitor.agents.monitor import run_tick
    tick_id = run_tick(mode="simulated")
    return {"tick_id": tick_id}

