"""Verify recovered files against their latest snapshots in Claude Code transcripts.

For each target file, walk every transcript and find:
  - The LATEST Read tool_result that shows the full file (no offset/limit)
  - The LATEST Write tool_input that wrote the file
Then compare byte-length and line-count to the current on-disk file.
"""
import json
import os
import re
from pathlib import Path
from glob import glob

PROJECTS = r"C:\Users\koush\.claude\projects"
REPO = Path(r"E:\Workspace\Hiive\deal-pipeline-monitoring-agent")

# Files to verify — (display name, on-disk absolute path, canonical suffix patterns to match against tool_input.file_path)
TARGETS = {
    "spec.md":          "specs/001-deal-pipeline-monitor/spec.md",
    "plan.md":          "specs/001-deal-pipeline-monitor/plan.md",
    "research.md":      "specs/001-deal-pipeline-monitor/research.md",
    "data-model.md":    "specs/001-deal-pipeline-monitor/data-model.md",
    "quickstart.md":    "specs/001-deal-pipeline-monitor/quickstart.md",
    "tasks.md":         "specs/001-deal-pipeline-monitor/tasks.md",
    "requirements.md":  "specs/001-deal-pipeline-monitor/checklists/requirements.md",
    "llm-schemas.md":   "specs/001-deal-pipeline-monitor/contracts/llm-schemas.md",
    "http-routes.md":   "specs/001-deal-pipeline-monitor/contracts/http-routes.md",
    "eval-scenario-schema.md": "specs/001-deal-pipeline-monitor/contracts/eval-scenario-schema.md",
    "BUILD_PLAN.md":    "BUILD_PLAN.md",
    "PROJECT_CONTEXT.md":"PROJECT_CONTEXT.md",
}

# Agent context file candidates to look for in any Write/Edit
AGENT_CTX_NAMES = ["CLAUDE.md", "AGENTS.md", "GEMINI.md", "copilot-instructions.md"]


def norm(p):
    """Normalize a path so it matches across worktrees and separator styles."""
    if not p:
        return ""
    p = p.replace("\\", "/")
    # Strip any worktree prefix
    p = re.sub(r".*?/\.claude/worktrees/[^/]+/", "", p)
    # Strip repo-root prefix
    p = re.sub(r".*?/deal-pipeline-monitoring-agent/", "", p)
    return p.lstrip("/")


def matches(target_suffix, file_path):
    n = norm(file_path)
    return n.endswith(target_suffix)


def walk_tools(obj, cb):
    """Recursively walk a JSON node, calling cb(kind, item) for every tool_use and tool_result."""
    if isinstance(obj, dict):
        t = obj.get("type")
        if t == "tool_use":
            cb("tool_use", obj)
        elif t == "tool_result":
            cb("tool_result", obj)
        for v in obj.values():
            walk_tools(v, cb)
    elif isinstance(obj, list):
        for v in obj:
            walk_tools(v, cb)


def extract_read_content(result):
    """Given a tool_result for a Read, return the reconstructed file text (strip cat -n prefixes)."""
    content = result.get("content")
    if isinstance(content, list):
        text = "".join(c.get("text", "") for c in content if isinstance(c, dict))
    elif isinstance(content, str):
        text = content
    else:
        return None
    # Strip leading "<line>\t" prefix from each line
    lines = []
    for line in text.split("\n"):
        m = re.match(r"^\s*(\d+)\t(.*)$", line)
        if m:
            lines.append(m.group(2))
        else:
            # Non-numbered line — likely system notice; skip
            pass
    return "\n".join(lines) if lines else None


def main():
    transcripts = []
    for d in glob(os.path.join(PROJECTS, "E--Workspace-Hiive-deal-pipeline-monitoring-agent*")):
        for f in glob(os.path.join(d, "*.jsonl")):
            transcripts.append(f)
    print(f"Scanning {len(transcripts)} transcripts...\n")

    # For each target: collect (timestamp, source, kind, length_chars, length_lines, preview_last_line)
    sightings = {name: [] for name in TARGETS}
    agent_sightings = []

    for tf in transcripts:
        try:
            with open(tf, "r", encoding="utf-8") as fp:
                for line_idx, raw in enumerate(fp):
                    try:
                        entry = json.loads(raw)
                    except json.JSONDecodeError:
                        continue
                    ts = entry.get("timestamp", "") or entry.get("created_at", "")

                    # We need both the tool_use (to know file_path) and the tool_result.
                    # Easier: when we see tool_use Write/Edit/Read, record file_path; when tool_result arrives, match by id.
                    def callback(kind, item):
                        if kind == "tool_use":
                            name = item.get("name")
                            inp = item.get("input", {}) or {}
                            fp_ = inp.get("file_path", "")
                            if not fp_:
                                return
                            # Write — full content in input
                            if name == "Write":
                                body = inp.get("content", "")
                                for target_name, suffix in TARGETS.items():
                                    if matches(suffix, fp_):
                                        sightings[target_name].append(
                                            (ts, os.path.basename(tf), "Write",
                                             len(body), body.count("\n") + (1 if body and not body.endswith("\n") else 0),
                                             body[-120:] if body else "")
                                        )
                                # Agent ctx file?
                                base = os.path.basename(fp_.replace("\\", "/"))
                                if base in AGENT_CTX_NAMES:
                                    agent_sightings.append((ts, os.path.basename(tf), "Write", fp_, len(body)))
                            elif name == "Edit":
                                # Edit doesn't give us full content — note it but don't measure
                                for target_name, suffix in TARGETS.items():
                                    if matches(suffix, fp_):
                                        sightings[target_name].append(
                                            (ts, os.path.basename(tf), "Edit", None, None,
                                             f"old→new: {(inp.get('old_string','') or '')[:50]}")
                                        )
                                base = os.path.basename(fp_.replace("\\", "/"))
                                if base in AGENT_CTX_NAMES:
                                    agent_sightings.append((ts, os.path.basename(tf), "Edit", fp_, None))
                            elif name == "Read":
                                # Check for full-file reads (no offset, no limit)
                                if inp.get("offset") is None and inp.get("limit") is None:
                                    # Record file_path for matching in tool_result
                                    item["_target_match"] = None
                                    for target_name, suffix in TARGETS.items():
                                        if matches(suffix, fp_):
                                            item["_target_match"] = target_name
                                            break
                        elif kind == "tool_result":
                            # No direct link here — skip. (We'd need to resolve by id; instead we handle Read below.)
                            pass

                    walk_tools(entry, callback)
                    # Second pass: handle full-file Read results by scanning message structure
                    # Claude Code JSONL interleaves assistant tool_use and user tool_result entries.
                    # When this entry IS a user-tool_result, try to find which tool_use id it matches
                    # by scanning prior entries. Simpler: walk content for tool_result and extract text.
                    try:
                        msg = entry.get("message", {}) or {}
                        role = msg.get("role")
                        if role == "user":
                            for c in msg.get("content", []) or []:
                                if isinstance(c, dict) and c.get("type") == "tool_result":
                                    use_id = c.get("tool_use_id")
                                    text = extract_read_content(c)
                                    if text is None:
                                        continue
                                    # Find the tool_use entry with that id earlier in file — expensive.
                                    # Instead, stash result by id in a side cache.
                                    RESULT_CACHE[use_id] = (ts, os.path.basename(tf), text)
                    except Exception:
                        pass
        except Exception as e:
            print(f"WARN {tf}: {e}")

    # Second pass: resolve Read tool_use -> tool_result by re-walking files
    for tf in transcripts:
        try:
            with open(tf, "r", encoding="utf-8") as fp:
                for raw in fp:
                    try:
                        entry = json.loads(raw)
                    except json.JSONDecodeError:
                        continue
                    msg = entry.get("message", {}) or {}
                    if msg.get("role") != "assistant":
                        continue
                    for c in msg.get("content", []) or []:
                        if isinstance(c, dict) and c.get("type") == "tool_use" and c.get("name") == "Read":
                            inp = c.get("input", {}) or {}
                            fp_path = inp.get("file_path", "")
                            if inp.get("offset") is not None or inp.get("limit") is not None:
                                continue
                            for target_name, suffix in TARGETS.items():
                                if matches(suffix, fp_path):
                                    use_id = c.get("id")
                                    hit = RESULT_CACHE.get(use_id)
                                    if hit:
                                        ts, src, text = hit
                                        sightings[target_name].append(
                                            (ts, src, "Read", len(text), text.count("\n") + 1, text[-120:])
                                        )
        except Exception:
            pass

    print("=" * 100)
    print(f"{'FILE':<30} {'DISK lines':>10} {'DISK chars':>11} {'LATEST src':<18} {'type':<6} {'lines':>6} {'chars':>7}")
    print("-" * 100)
    for name, suffix in TARGETS.items():
        disk = REPO / suffix
        if disk.exists():
            dtext = disk.read_text(encoding="utf-8", errors="replace")
            dlines = dtext.count("\n") + (0 if dtext.endswith("\n") else 1)
            dchars = len(dtext)
        else:
            dlines, dchars = -1, -1
        seen = sightings[name]
        seen.sort(key=lambda x: x[0] or "")
        latest = None
        # Prefer latest with a size (Write or Read), skip Edit-only
        for s in reversed(seen):
            if s[3] is not None:
                latest = s
                break
        if latest:
            _, src, kind, chars, lines, _ = latest
            print(f"{name:<30} {dlines:>10} {dchars:>11} {src:<18} {kind:<6} {lines:>6} {chars:>7}")
        else:
