    "eval-scenario-schema.md": "specs/001-deal-pipeline-monitor/contracts/eval-scenario-schema.md",
    "BUILD_PLAN.md":    "BUILD_PLAN.md",
    "PROJECT_CONTEXT.md":"PROJECT_CONTEXT.md",
    "CLAUDE.md":        "CLAUDE.md",
}


def norm(p):
    if not p:
        return ""
    p = p.replace("\\", "/")
    p = re.sub(r".*?/\.claude/worktrees/[^/]+/", "", p)
    p = re.sub(r".*?/deal-pipeline-monitoring-agent/", "", p)
    return p.lstrip("/")


def extract_read_text(tool_result):
    content = tool_result.get("content")
    if isinstance(content, list):
        text = "".join(c.get("text", "") for c in content if isinstance(c, dict))
    elif isinstance(content, str):
        text = content
    else:
        return None
    # Strip cat -n prefix
    lines = []
    for line in text.split("\n"):
        m = re.match(r"^\s*(\d+)\t(.*)$", line)
        if m:
            lines.append(m.group(2))
    if not lines:
        return None
    return "\n".join(lines) + "\n"


def load_all_events():
    """Yield (timestamp, source, use_id, tool, input, result_text) for every tool call in every transcript."""
    transcripts = []
    for d in glob(os.path.join(PROJECTS, "E--Workspace-Hiive-deal-pipeline-monitoring-agent*")):
        for f in glob(os.path.join(d, "*.jsonl")):
            transcripts.append(f)

    # Pass 1: collect all tool_use with their id, timestamp, input
    uses = {}  # id -> (ts, src, tool, input)
    # Pass 2: collect tool_result by id -> text
    results = {}  # id -> text

    for tf in transcripts:
        src = os.path.basename(tf)
        try:
            with open(tf, "r", encoding="utf-8") as fp:
                for raw in fp:
                    try:
                        entry = json.loads(raw)
                    except json.JSONDecodeError:
                        continue
                    ts = entry.get("timestamp", "")
                    msg = entry.get("message", {}) or {}
                    role = msg.get("role")
                    if role == "assistant":
                        for c in msg.get("content", []) or []:
                            if isinstance(c, dict) and c.get("type") == "tool_use":
                                uses[c.get("id")] = (ts, src, c.get("name"), c.get("input", {}) or {})
                    elif role == "user":
                        for c in msg.get("content", []) or []:
                            if isinstance(c, dict) and c.get("type") == "tool_result":
                                txt = extract_read_text(c)
                                if txt is not None:
                                    results[c.get("tool_use_id")] = txt
        except Exception as e:
            print(f"WARN {tf}: {e}")

    for uid, (ts, src, tool, inp) in uses.items():
        yield (ts, src, uid, tool, inp, results.get(uid))


def main():
    events = list(load_all_events())
    print(f"Loaded {len(events)} tool-use events from transcripts\n")

    for display_name, suffix in TARGETS.items():
        # Filter events for this target
        matched = []
        for ts, src, uid, tool, inp, rtext in events:
            fp_ = inp.get("file_path", "")
            if not fp_:
                continue
            if norm(fp_).endswith(suffix):
                matched.append((ts, src, uid, tool, inp, rtext))
        matched.sort(key=lambda x: x[0] or "")

        print(f"{'=' * 100}")
        print(f"FILE: {display_name}  ({suffix})")
        print(f"  {len(matched)} events total")

        disk_path = REPO / suffix
        if disk_path.exists():
            dtext = disk_path.read_text(encoding="utf-8", errors="replace")
            print(f"  DISK: {len(dtext)} chars, {dtext.count(chr(10))} newlines, "
                  f"last_line={dtext.rstrip().splitlines()[-1][:80] if dtext.strip() else '(empty)'!r}")
        else:
            dtext = None
            print(f"  DISK: MISSING")

        # Find latest full snapshot (Read with no offset/limit AND result, or Write)
        snapshot_idx = None
        for i in range(len(matched) - 1, -1, -1):
            ts, src, uid, tool, inp, rtext = matched[i]
            if tool == "Write":
                snapshot_idx = i
                break
            if tool == "Read" and inp.get("offset") is None and inp.get("limit") is None and rtext is not None:
                snapshot_idx = i
                break

        # Print event list
        print("  Events (tool | time | src | detail):")
        for i, (ts, src, uid, tool, inp, rtext) in enumerate(matched):
            marker = "  *" if i == snapshot_idx else "   "
            if tool == "Write":
                sz = len(inp.get("content", ""))
                print(f"{marker} [{i:>3}] {tool:<5} {ts[:19]} {src[:14]}  Write {sz}ch")
            elif tool == "Edit":
                old = (inp.get("old_string", "") or "")[:50].replace("\n", "\\n")
                new = (inp.get("new_string", "") or "")[:50].replace("\n", "\\n")
                print(f"{marker} [{i:>3}] {tool:<5} {ts[:19]} {src[:14]}  {old!r} → {new!r}")
            elif tool == "Read":
                off = inp.get("offset")
                lim = inp.get("limit")
                rsz = len(rtext) if rtext else "n/a"
                detail = f"Read (full, {rsz}ch)" if off is None and lim is None else f"Read(off={off},lim={lim})"
                print(f"{marker} [{i:>3}] {tool:<5} {ts[:19]} {src[:14]}  {detail}")

        if snapshot_idx is None or dtext is None:
            print(f"  RESULT: cannot verify (no snapshot or no disk file)\n")
            continue

        # Reconstruct: start with snapshot text, apply Edits after it
        snap = matched[snapshot_idx]
        if snap[3] == "Write":
            state = snap[4].get("content", "")
        else:
            state = snap[5]  # Read result text

        for i in range(snapshot_idx + 1, len(matched)):
            ts, src, uid, tool, inp, rtext = matched[i]
            if tool == "Write":
                state = inp.get("content", "")
            elif tool == "Edit":
                old_s = inp.get("old_string", "")
                new_s = inp.get("new_string", "")
                if inp.get("replace_all"):
                    state = state.replace(old_s, new_s)
                else:
                    idx = state.find(old_s)
                    if idx < 0:
                        print(f"    WARN: Edit #{i} old_string NOT FOUND in state")
                    else:
                        state = state[:idx] + new_s + state[idx + len(old_s):]

        # Compare (normalize line endings for comparison since Windows CRLF differences may exist)
        a = state.replace("\r\n", "\n")
        b = dtext.replace("\r\n", "\n")
        if a == b:
            print(f"  RESULT: ✓ DISK MATCHES replayed state exactly ({len(a)} chars)\n")
        else:
            print(f"  RESULT: ✗ DISK MISMATCH  replay={len(a)}ch disk={len(b)}ch  diff={len(b) - len(a):+d}")
            # Show the mismatch
            # Find first differing offset
            lim = min(len(a), len(b))
            off = 0
            while off < lim and a[off] == b[off]:
                off += 1
            print(f"     first diff at offset {off}")
            print(f"     replay[{off}:{off+80}]: {a[off:off+80]!r}")
            print(f"     disk  [{off}:{off+80}]: {b[off:off+80]!r}")
            # Show tails
            print(f"     replay tail: {a[-120:]!r}")
            print(f"     disk   tail: {b[-120:]!r}")
            print()


if __name__ == "__main__":
    main()

