                if msg.get("role") != "assistant": continue
                for c in msg.get("content", []) or []:
                    if isinstance(c, dict) and c.get("type") == "tool_use":
                        if c.get("name") in ("Write", "Edit"):
                            fp_ = (c.get("input") or {}).get("file_path", "")
                            if fp_:
                                n = norm(fp_)
                                if n and (ts > touched.get(n, "")):
                                    touched[n] = ts

missing = []
for n in sorted(touched):
    # Skip paths that are clearly outside the repo (absolute references we couldn't canonicalize)
    if ":" in n or n.startswith(".tmp_") or n.startswith(".recovered/"):
