    disk = REPO / n
    if not disk.exists():
        missing.append((n, touched[n]))

print(f"Total distinct files Written/Edited: {len(touched)}")
print(f"Missing from disk now: {len(missing)}\n")
for n, ts in missing:
    print(f"  [{ts}]  {n}")

