{% extends "base.html" %}
{% block title %}{{ deal.deal_id }}{% if issuer %} · {{ issuer.name }}{% endif %} — Hiive{% endblock %}

{% block content %}
{% set sorted_obs = observations | sort(attribute='observed_at', reverse=True) | list %}
{% set latest_obs = sorted_obs | first if sorted_obs else none %}

<!-- Breadcrumb -->
<div class="flex items-center gap-2 text-[0.6875rem] text-on-surface-variant mb-4">
  <a href="/brief" class="hover:text-on-surface transition-colors">Daily Brief</a>
  <span class="text-outline-variant mx-0.5">›</span>
  <span class="text-on-surface font-medium">{{ deal.deal_id }}{% if issuer %} · {{ issuer.name }}{% endif %}</span>
</div>

<!-- Page header -->
<div class="flex items-start justify-between pb-4 border-b-[0.5px] border-outline-variant/50 mb-6">
  <div>
    <h1 class="text-[1.1875rem] font-semibold text-on-surface tracking-tight leading-snug">
      {{ deal.deal_id }}{% if issuer %}<span class="text-on-surface-variant font-normal"> · {{ issuer.name }}</span>{% endif %}
    </h1>
    <div class="flex items-center flex-wrap gap-2 mt-2">
      <span class="px-2 py-0.5 rounded-[4px] text-[0.625rem] font-medium text-on-surface bg-surface-container-low border-[0.5px] border-outline-variant/50 uppercase tracking-widest">{{ deal.stage | replace('_', ' ') }}</span>
      {% if latest_obs %}
        {% if latest_obs.severity == 'escalate' %}
          <span class="px-2 py-0.5 rounded-[4px] text-[0.625rem] font-bold bg-error-container text-error border-[0.5px] border-error/10">ESCALATE</span>
        {% elif latest_obs.severity == 'act' %}
          <span class="px-2 py-0.5 rounded-[4px] text-[0.625rem] font-bold bg-primary-fixed text-primary-container border-[0.5px] border-primary-container/10">ACT</span>
        {% elif latest_obs.severity == 'watch' %}
          <span class="px-2 py-0.5 rounded-[4px] text-[0.625rem] font-bold bg-tertiary-fixed text-tertiary border-[0.5px] border-tertiary/10">WATCH</span>
        {% elif latest_obs.severity == 'info' %}
          <span class="px-2 py-0.5 rounded-[4px] text-[0.625rem] font-bold bg-surface-container text-on-surface-variant border-[0.5px] border-outline-variant/50">INFO</span>
        {% endif %}
      {% endif %}
      {% if issuer %}
        <span class="text-[0.6875rem] text-on-surface-variant">{{ deal.shares | int | format_number }} shares @ ${{ "%.2f"|format(deal.price_per_share) }}</span>
      {% endif %}
      {% if deal.rofr_deadline %}
        <span class="text-[0.6875rem] text-on-surface-variant">ROFR: {{ deal.rofr_deadline[:10] }}</span>
      {% endif %}
    </div>
  </div>
  <div class="flex items-center gap-3 flex-shrink-0 mt-0.5">
    {% if debug %}
      <a href="/debug/deal/{{ deal.deal_id }}" class="text-[0.6875rem] font-mono text-primary-container hover:underline transition-colors">debug ↗</a>
    {% else %}
      <a href="?debug=1" class="text-[0.6875rem] text-on-surface-variant hover:text-on-surface transition-colors">debug</a>
    {% endif %}
  </div>
</div>

<!-- 3-column grid: Facts+Interventions | Agent Analysis | Event Timeline -->
<div class="grid grid-cols-1 lg:grid-cols-4 gap-5 items-start">

  <!-- ── Left (1/4): Deal Facts + Interventions ── -->
  <div class="lg:col-span-1 flex flex-col gap-4">

    <!-- Deal Facts -->
    <div class="border-[0.5px] border-outline-variant/50 rounded-lg bg-surface-container-lowest overflow-hidden">
      <div class="px-4 py-2 bg-surface-container-low border-b-[0.5px] border-outline-variant/50">
        <span class="text-[0.625rem] font-medium text-on-surface-variant uppercase tracking-widest">Deal Facts</span>
      </div>
      <div class="px-4 py-1">
        {% macro fact_row(label, value, vc='') %}
        <div class="flex items-baseline justify-between gap-3 py-2 border-b-[0.5px] border-outline-variant/50 last:border-b-0">
          <span class="text-[0.625rem] text-on-surface-variant uppercase tracking-widest shrink-0">{{ label }}</span>
          <span class="text-[0.8125rem] font-medium {{ vc or 'text-on-surface' }} text-right truncate">{{ value or '—' }}</span>
        </div>
        {% endmacro %}
        {{ fact_row("Stage entered", deal.stage_entered_at[:10] if deal.stage_entered_at else '—') }}
        {{ fact_row("Responsible", deal.responsible_party | replace('_', ' ') if deal.responsible_party else '—') }}
        {{ fact_row("ROFR deadline", deal.rofr_deadline[:10] if deal.rofr_deadline else 'None') }}
        {{ fact_row("Buyer", deal.buyer_id) }}
      </div>
    </div>

    <!-- Interventions -->
    <div class="border-[0.5px] border-outline-variant/50 rounded-lg bg-surface-container-lowest overflow-hidden">
      <div class="px-4 py-2 bg-surface-container-low border-b-[0.5px] border-outline-variant/50 flex items-center justify-between">
        <span class="text-[0.625rem] font-medium text-on-surface-variant uppercase tracking-widest">Interventions</span>
        <span class="text-[0.6875rem] tabular-nums text-on-surface-variant">{{ interventions | length }}</span>
      </div>
      {% if interventions %}
        <div class="flex flex-col">
          {% for iv in interventions | sort(attribute='created_at', reverse=True) %}
          <div class="px-4 py-3 {% if not loop.first %}border-t-[0.5px] border-outline-variant/50{% endif %}">
            <div class="flex items-center gap-2 mb-1 flex-wrap">
              <span class="text-[0.625rem] font-mono text-on-surface-variant">{{ iv.created_at[:10] }}</span>
              <span class="inline-flex rounded-[4px] bg-surface-container px-1.5 py-0.5 text-[0.625rem] text-on-surface-variant">{{ iv.intervention_type | replace('_', ' ') }}</span>
              <span class="text-[0.625rem] font-semibold
                {% if iv.status in ['approved', 'edited'] %}text-secondary
                {% elif iv.status == 'pending' %}text-tertiary
                {% else %}text-on-surface-variant{% endif %}
              ">{{ iv.status }}</span>
            </div>
            <p class="text-[0.75rem] text-on-surface-variant leading-snug">{{ iv.draft_subject or iv.draft_body[:80] }}</p>
          </div>
          {% endfor %}
        </div>
      {% else %}
        <div class="px-4 py-6 text-center">
          <p class="text-[0.75rem] text-on-surface-variant">No interventions drafted yet.</p>
        </div>
      {% endif %}
    </div>

  </div>

  <!-- ── Center (2/4): Agent Analysis ── -->
  <div class="lg:col-span-2 flex flex-col gap-4">

    {% if sorted_obs %}

      <!-- Latest observation -->
      <div class="border-[0.5px] border-outline-variant/50 rounded-lg bg-surface-container-lowest overflow-hidden">
        <div class="px-4 py-2 bg-surface-container-low border-b-[0.5px] border-outline-variant/50 flex items-center justify-between">
          <span class="text-[0.625rem] font-medium text-on-surface-variant uppercase tracking-widest">Agent Analysis</span>
          <span class="text-[0.6875rem] font-mono text-on-surface-variant">{{ latest_obs.observed_at[:16] }}</span>
        </div>
        <div class="px-5 py-4 space-y-5">

          {% if latest_obs.reasoning_parsed.get('error') %}
            <div class="rounded-[4px] border-[0.5px] border-outline-variant/50 bg-error-container/40 px-3 py-2.5 text-[0.6875rem] text-error">
              LLM error: {{ latest_obs.reasoning_parsed.get('error') }}
            </div>
          {% else %}

            <!-- Severity rationale — background tint, no side stripe -->
            {% set sev = latest_obs.severity %}
            {% if latest_obs.reasoning_parsed.get('severity_rationale') %}
            <div>
              <span class="text-[0.625rem] font-medium text-on-surface-variant uppercase tracking-widest block mb-2">Severity Rationale</span>
              <p class="text-[0.8125rem] text-on-surface leading-relaxed px-3 py-2.5 rounded-[4px] border-[0.5px]
                {% if sev == 'escalate' %}bg-error-container/40 border-error/20
                {% elif sev == 'act' %}bg-primary-fixed/60 border-primary-container/20
                {% elif sev == 'watch' %}bg-tertiary-fixed/40 border-tertiary/20
                {% else %}bg-surface-container border-outline-variant/50{% endif %}
              ">{{ latest_obs.reasoning_parsed.get('severity_rationale') }}</p>
            </div>
            {% endif %}

            <!-- Dimensions triggered -->
            {% set dims = latest_obs.reasoning_parsed.get('dimensions_triggered', []) %}
            {% if dims %}
            <div>
              <span class="text-[0.625rem] font-medium text-on-surface-variant uppercase tracking-widest block mb-2">Dimensions Triggered</span>
              <div class="flex flex-wrap gap-1.5">
                {% for dim in dims %}
                  <span class="inline-flex rounded-[4px] bg-surface-container px-1.5 py-0.5 text-[0.6875rem] text-on-surface-variant">{{ dim | replace('_', ' ') }}</span>
                {% endfor %}
              </div>
            </div>
            {% endif %}

            <!-- Enrichment chain (collapsible) -->
            {% set chain = latest_obs.reasoning_parsed.get('enrichment_chain', []) %}
            {% if chain %}
            <div x-data="{ showChain: false }">
              <button
                x-on:click="showChain = !showChain"
                class="flex items-center gap-1.5 text-[0.6875rem] text-on-surface-variant hover:text-on-surface transition-colors mb-2"
              >
                <span x-text="showChain ? '↑' : '↓'" class="font-mono"></span>
                <span class="uppercase tracking-widest font-medium">Enrichment steps ({{ chain|length }})</span>
              </button>
              <div x-show="showChain" x-cloak class="flex flex-col gap-1.5">
                {% for step in chain %}
                <div class="rounded-[4px] bg-surface-container border-[0.5px] border-outline-variant/50 px-3 py-2 text-[0.6875rem]">
                  <span class="font-medium text-on-surface">{{ step.get('tool_called', '?') | replace('_', ' ') }}</span>
                  {% if step.get('rationale') %}<span class="text-on-surface-variant"> — {{ step.get('rationale') }}</span>{% endif %}
                </div>
                {% endfor %}
              </div>
            </div>
            {% else %}
            <p class="text-[0.6875rem] text-on-surface-variant italic">No enrichment performed — initial signals were sufficient.</p>
            {% endif %}

          {% endif %}

          {% if debug %}
          <div>
            <span class="text-[0.625rem] font-medium text-on-surface-variant uppercase tracking-widest block mb-1.5">Debug — Raw reasoning</span>
            <pre class="rounded-[4px] bg-surface-container border-[0.5px] border-outline-variant/50 px-3 py-2 text-[0.6875rem] text-on-surface-variant overflow-auto max-h-64">{{ latest_obs.reasoning_parsed | tojson(indent=2) }}</pre>
          </div>
          {% endif %}

        </div>
      </div>

      <!-- Older observations (collapsible) -->
      {% if sorted_obs | length > 1 %}
      <div x-data="{ expanded: false }" class="border-[0.5px] border-outline-variant/50 rounded-lg bg-surface-container-lowest overflow-hidden">
        <button
          x-on:click="expanded = !expanded"
          class="w-full px-4 py-3 flex items-center justify-between hover:bg-surface-container-low transition-colors"
        >
          <span class="text-[0.8125rem] font-medium text-on-surface-variant">Older observations ({{ sorted_obs | length - 1 }})</span>
          <span x-text="expanded ? '↑' : '↓'" class="text-[0.6875rem] font-mono text-on-surface-variant"></span>
        </button>
        <div x-show="expanded" x-cloak>
          {% for obs in sorted_obs[1:] %}
          <div class="border-t-[0.5px] border-outline-variant/50 px-4 py-3" x-data="{ show: false }">
            <div class="flex items-center justify-between gap-3">
              <div class="flex items-center gap-2 flex-wrap">
                <span class="text-[0.6875rem] font-mono text-on-surface-variant">{{ obs.observed_at[:16] }}</span>
                {% if obs.severity == 'escalate' %}
                  <span class="inline-flex items-center px-1.5 py-0.5 rounded-[4px] text-[0.625rem] font-bold bg-error-container text-error border-[0.5px] border-error/10">ESCALATE</span>
                {% elif obs.severity == 'act' %}
                  <span class="inline-flex items-center px-1.5 py-0.5 rounded-[4px] text-[0.625rem] font-bold bg-primary-fixed text-primary-container border-[0.5px] border-primary-container/10">ACT</span>
                {% elif obs.severity == 'watch' %}
                  <span class="inline-flex items-center px-1.5 py-0.5 rounded-[4px] text-[0.625rem] font-bold bg-tertiary-fixed text-tertiary border-[0.5px] border-tertiary/10">WATCH</span>
                {% elif obs.severity == 'info' %}
                  <span class="inline-flex items-center px-1.5 py-0.5 rounded-[4px] text-[0.625rem] font-bold bg-surface-container text-on-surface-variant border-[0.5px] border-outline-variant/50">INFO</span>
                {% endif %}
                {% for dim in obs.reasoning_parsed.get('dimensions_triggered', []) %}
                  <span class="inline-flex rounded-[4px] bg-surface-container px-1.5 py-0.5 text-[0.6875rem] text-on-surface-variant">{{ dim | replace('_', ' ') }}</span>
                {% endfor %}
              </div>
              <button
                x-on:click="show = !show"
                class="text-[0.6875rem] text-on-surface-variant hover:text-on-surface transition-colors shrink-0"
                x-text="show ? '↑' : 'Detail'"
              ></button>
            </div>
            <div x-show="show" x-cloak class="mt-3 space-y-2">
              {% if obs.reasoning_parsed.get('error') %}
                <div class="rounded-[4px] border-[0.5px] border-outline-variant/50 bg-error-container/40 px-3 py-2 text-[0.6875rem] text-error">LLM error: {{ obs.reasoning_parsed.get('error') }}</div>
              {% else %}
                <p class="text-[0.75rem] text-on-surface-variant leading-relaxed">{{ obs.reasoning_parsed.get('severity_rationale', '') }}</p>
              {% endif %}
              {% if debug %}
                <pre class="rounded-[4px] bg-surface-container border-[0.5px] border-outline-variant/50 px-3 py-2 text-[0.6875rem] text-on-surface-variant overflow-auto max-h-48">{{ obs.reasoning_parsed | tojson(indent=2) }}</pre>
              {% endif %}
            </div>
          </div>
          {% endfor %}
        </div>
      </div>
      {% endif %}

    {% else %}
      <div class="border-[0.5px] border-outline-variant/50 rounded-lg bg-surface-container-lowest px-4 py-12 text-center">
        <p class="text-[0.8125rem] text-on-surface-variant">No observations yet — advance the simulation to analyze this deal.</p>
      </div>
    {% endif %}

  </div>

  <!-- ── Right (1/4): Event Timeline ── -->
  <div class="lg:col-span-1">
    <div class="border-[0.5px] border-outline-variant/50 rounded-lg bg-surface-container-lowest overflow-hidden">
      <div class="px-4 py-2 bg-surface-container-low border-b-[0.5px] border-outline-variant/50 flex items-center justify-between">
        <span class="text-[0.625rem] font-medium text-on-surface-variant uppercase tracking-widest">Event Timeline</span>
        <span class="text-[0.6875rem] tabular-nums text-on-surface-variant">{{ events | length }}</span>
      </div>
      {% if events %}
        <div class="px-4 py-4">
          <!-- Vertical timeline: dot on vertical line, content to the right -->
          <div class="relative ml-1">
            <div class="absolute left-0 top-2 bottom-0 border-l-[0.5px] border-outline-variant"></div>
            <div class="flex flex-col gap-5">
              {% for ev in events | sort(attribute='occurred_at', reverse=True) %}
              <div class="relative pl-5">
                <!-- Timeline dot, centered on the vertical line -->
                <div class="absolute left-0 top-[0.3125rem] -translate-x-1/2 w-2 h-2 rounded-full border-[1.5px] border-surface-container-lowest
                  {% if ev.event_type in ['comm_outbound', 'comm_sent_agent_recommended'] %}bg-primary-container
                  {% elif ev.event_type == 'comm_inbound' %}bg-secondary
                  {% elif ev.event_type == 'stage_transition' %}bg-on-surface-variant
                  {% else %}bg-outline-variant{% endif %}
                "></div>
                <span class="text-[0.625rem] text-on-surface-variant block">{{ ev.occurred_at[:10] }}</span>
                <p class="text-[0.75rem] font-medium text-on-surface mt-0.5 leading-snug">{{ ev.summary }}</p>
                <span class="text-[0.625rem] text-on-surface-variant mt-0.5 block">{{ ev.event_type | replace('_', ' ') }}</span>
              </div>
              {% endfor %}
            </div>
          </div>
        </div>
      {% else %}
        <div class="px-4 py-8 text-center">
          <p class="text-[0.75rem] text-on-surface-variant">No events yet.</p>
        </div>
      {% endif %}
    </div>
  </div>

</div>
{% endblock %}

