26	        {% elif latest_obs.severity == 'act' %}
27	          <span class="px-2 py-0.5 rounded-[4px] text-[0.625rem] font-bold bg-primary-fixed text-primary-container border-[0.5px] border-primary-container/10">ACT</span>
